-- EFF Membership Hub: run once in the shared REACH Supabase SQL Editor.
create table if not exists public.eff_member_profiles(user_id uuid primary key references auth.users(id) on delete cascade,full_name text not null,preferred_name text,school text not null,chapter text,major text,graduation_year integer,created_at timestamptz not null default now());
create table if not exists public.eff_membership_records(user_id uuid primary key references auth.users(id) on delete cascade,joinit_status text not null default 'unverified' check(joinit_status in ('unverified','pending','verified','mismatch','revoked')),membership_status text not null default 'candidate' check(membership_status in ('candidate','active','inactive','alumni')),access_revoked boolean not null default false,created_at timestamptz not null default now());
create table if not exists public.eff_member_module_completions(id uuid primary key default gen_random_uuid(),user_id uuid not null references auth.users(id) on delete cascade,module_key text not null,completed_at timestamptz not null default now(),unique(user_id,module_key));
create table if not exists public.eff_member_service_hours(id uuid primary key default gen_random_uuid(),user_id uuid not null references auth.users(id) on delete cascade,title text not null,hours numeric(6,2) not null check(hours>0),reflection text,status text not null default 'pending' check(status in ('pending','approved','rejected')),created_at timestamptz not null default now());
create table if not exists public.eff_member_fundraising(id uuid primary key default gen_random_uuid(),user_id uuid not null references auth.users(id) on delete cascade,amount numeric(10,2) not null check(amount>=0),note text,status text not null default 'pending' check(status in ('pending','approved','rejected')),created_at timestamptz not null default now());
create or replace function public.eff_create_membership_record() returns trigger language plpgsql security definer set search_path=public as $$ begin insert into public.eff_membership_records(user_id) values(new.user_id) on conflict(user_id) do nothing; return new; end; $$;
drop trigger if exists eff_profile_creates_record on public.eff_member_profiles;create trigger eff_profile_creates_record after insert on public.eff_member_profiles for each row execute function public.eff_create_membership_record();
alter table public.eff_member_profiles enable row level security;alter table public.eff_membership_records enable row level security;alter table public.eff_member_module_completions enable row level security;alter table public.eff_member_service_hours enable row level security;alter table public.eff_member_fundraising enable row level security;
create or replace function public.eff_membership_staff() returns boolean language sql stable security definer set search_path=public as $$ select exists(select 1 from public.eff_chapter_roles where user_id=auth.uid() and role='national_staff') $$;
drop policy if exists "member owns profile" on public.eff_member_profiles;create policy "member owns profile" on public.eff_member_profiles for all to authenticated using(user_id=auth.uid()) with check(user_id=auth.uid());
drop policy if exists "member sees record" on public.eff_membership_records;create policy "member sees record" on public.eff_membership_records for select to authenticated using(user_id=auth.uid());
drop policy if exists "member owns modules" on public.eff_member_module_completions;create policy "member owns modules" on public.eff_member_module_completions for all to authenticated using(user_id=auth.uid()) with check(user_id=auth.uid());
drop policy if exists "member owns service" on public.eff_member_service_hours;create policy "member owns service" on public.eff_member_service_hours for all to authenticated using(user_id=auth.uid()) with check(user_id=auth.uid());
drop policy if exists "member owns fundraising" on public.eff_member_fundraising;create policy "member owns fundraising" on public.eff_member_fundraising for all to authenticated using(user_id=auth.uid()) with check(user_id=auth.uid());
drop policy if exists "national staff manages membership" on public.eff_member_profiles;create policy "national staff manages membership" on public.eff_member_profiles for all to authenticated using(public.eff_membership_staff()) with check(public.eff_membership_staff());
create policy "national staff manages records" on public.eff_membership_records for all to authenticated using(public.eff_membership_staff()) with check(public.eff_membership_staff());
create policy "national staff manages modules" on public.eff_member_module_completions for all to authenticated using(public.eff_membership_staff()) with check(public.eff_membership_staff());
create policy "national staff manages service" on public.eff_member_service_hours for all to authenticated using(public.eff_membership_staff()) with check(public.eff_membership_staff());
create policy "national staff manages fundraising" on public.eff_member_fundraising for all to authenticated using(public.eff_membership_staff()) with check(public.eff_membership_staff());
